const path=require("path"),mongoose=require("mongoose");require("dotenv").config({path:path.join(__dirname,"..",".env")});const User=require("../src/models/User"),{verify:verifyPassword}=require("../src/lib/passwords"),MONGODB_URI=process.env.MONGODB_URI||"mongodb+srv://shivanshbhardwaj2015_db_user:bbbbbbbb@cluster0.zda2259.mongodb.net/";async function testPassword(){try{await mongoose.connect(MONGODB_URI,{useNewUrlParser:!0,useUnifiedTopology:!0}),console.log("Connected to MongoDB");const o=await User.findOne({email:"admin"});if(o){console.log('User found with email "admin"'),console.log("Password hash:",o.passwordHash);const s=await verifyPassword("admin",o.passwordHash);console.log("Password verification result:",s)}else console.log('No user found with email "admin"');await mongoose.connection.close(),console.log("Done")}catch(o){console.error("Error:",o),process.exit(1)}}testPassword();